INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Какой документ устанавливает требования к структуре образовательной программы дошкольного образования?', '["ФГОС ДО", "СанПиН", "Устав ДОУ", "Учебный план"]', 0, 1),
(@olympiad_id, 'Сколько образовательных областей выделяет ФГОС ДО?', '["3", "5", "7", "10"]', 1, 2),
(@olympiad_id, 'Какая из перечисленных областей входит в ФГОС ДО?', '["Познавательное развитие", "Трудовое воспитание", "Профессиональная подготовка", "Экономическая грамотность"]', 0, 3),
(@olympiad_id, 'Что является основной формой деятельности в дошкольном возрасте согласно ФГОС ДО?', '["Учебное занятие", "Самостоятельная работа", "Игра", "Лекция"]', 2, 4),
(@olympiad_id, 'ФГОС ДО ориентирован на:', '["Получение академических знаний", "Индивидуализацию дошкольного образования", "Подготовку к ЕГЭ", "Формирование профессиональных навыков"]', 1, 5),
(@olympiad_id, 'Какой принцип НЕ относится к принципам ФГОС ДО?', '["Поддержка инициативы детей", "Содействие и сотрудничество", "Конкурентность обучения", "Приобщение к социокультурным нормам"]', 2, 6),
(@olympiad_id, 'Целевые ориентиры ФГОС ДО — это:', '["Оценки за экзамены", "Социально-нормативные возрастные характеристики возможных достижений ребёнка", "Требования к педагогу", "Учебные стандарты"]', 1, 7),
(@olympiad_id, 'Образовательная программа ДОУ разрабатывается на основе:', '["ФГОС ДО", "Личного опыта заведующего", "Программы начальной школы", "Пожеланий родителей"]', 0, 8),
(@olympiad_id, 'К какой образовательной области относится обучение грамоте в ДОУ?', '["Физическое развитие", "Речевое развитие", "Художественно-эстетическое развитие", "Социально-коммуникативное развитие"]', 1, 9),
(@olympiad_id, 'Содержание программы должно обеспечивать развитие:', '["Только интеллектуальных способностей", "Только физических способностей", "Личности, мотивации и способностей детей в различных видах деятельности", "Только творческих способностей"]', 2, 10);
