INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Какой вид планирования является обязательным для воспитателя по ФГОС ДО?', '["Календарно-тематическое планирование", "Поурочное планирование", "Бизнес-планирование", "Стратегическое планирование"]', 0, 1),
(@olympiad_id, 'Что такое индивидуальный образовательный маршрут ребёнка?', '["Расписание кружков", "Персональная траектория развития с учётом особенностей ребёнка", "Маршрут от дома до детского сада", "План питания"]', 1, 2),
(@olympiad_id, 'Какая форма работы с родителями рекомендуется ФГОС ДО?', '["Партнёрское взаимодействие", "Полное невмешательство", "Только родительские собрания", "Контроль домашней обстановки"]', 0, 3),
(@olympiad_id, 'Мониторинг развития ребёнка по ФГОС ДО проводится с целью:', '["Выставления оценок", "Индивидуализации образования и оптимизации работы с группой", "Составления рейтинга детей", "Определения готовности к школе"]', 1, 4),
(@olympiad_id, 'Какой подход к образовательному процессу предполагает ФГОС ДО?', '["Системно-деятельностный", "Авторитарный", "Репродуктивный", "Академический"]', 0, 5),
(@olympiad_id, 'РППС по ФГОС ДО должна быть:', '["Статичной и неизменной", "Содержательно-насыщенной, трансформируемой, полифункциональной", "Максимально заполненной игрушками", "Одинаковой для всех возрастов"]', 1, 6),
(@olympiad_id, 'Кто участвует в разработке образовательной программы ДОУ?', '["Только заведующий", "Педагогический коллектив ДОУ", "Только методист", "Министерство образования"]', 1, 7),
(@olympiad_id, 'Какой формат образовательной деятельности приоритетен в ДОУ?', '["Фронтальное занятие", "Совместная и самостоятельная деятельность детей", "Лекция", "Индивидуальный опрос"]', 1, 8),
(@olympiad_id, 'Часть программы, формируемая участниками образовательных отношений, составляет:', '["100% программы", "Не более 40% от общего объёма", "Не более 10%", "Не менее 80%"]', 1, 9),
(@olympiad_id, 'Что является результатом освоения образовательной программы ДО?', '["Оценки и баллы", "Целевые ориентиры", "Аттестат", "Сертификат"]', 1, 10);
