INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Формирование элементарных математических представлений относится к области:', '["Речевое развитие", "Познавательное развитие", "Социально-коммуникативное развитие", "Физическое развитие"]', 1, 1),
(@olympiad_id, 'К какой области относится приобщение к музыкальному искусству?', '["Художественно-эстетическое развитие", "Речевое развитие", "Познавательное развитие", "Социально-коммуникативное развитие"]', 0, 2),
(@olympiad_id, 'Формирование основ безопасного поведения относится к области:', '["Физическое развитие", "Познавательное развитие", "Социально-коммуникативное развитие", "Речевое развитие"]', 2, 3),
(@olympiad_id, 'Развитие общения ребёнка со взрослыми и сверстниками — задача области:', '["Познавательное развитие", "Социально-коммуникативное развитие", "Речевое развитие", "Художественно-эстетическое развитие"]', 1, 4),
(@olympiad_id, 'Овладение подвижными играми с правилами относится к области:', '["Познавательное развитие", "Социально-коммуникативное развитие", "Речевое развитие", "Физическое развитие"]', 3, 5),
(@olympiad_id, 'Знакомство с детской литературой входит в область:', '["Художественно-эстетическое развитие", "Познавательное развитие", "Речевое развитие", "Социально-коммуникативное развитие"]', 2, 6),
(@olympiad_id, 'Развитие воображения и творческой активности — задача области:', '["Физическое развитие", "Познавательное развитие", "Речевое развитие", "Социально-коммуникативное развитие"]', 1, 7),
(@olympiad_id, 'Становление саморегуляции в двигательной сфере относится к:', '["Социально-коммуникативное развитие", "Познавательное развитие", "Физическое развитие", "Речевое развитие"]', 2, 8),
(@olympiad_id, 'Формирование позитивных установок к труду — задача области:', '["Познавательное развитие", "Художественно-эстетическое развитие", "Физическое развитие", "Социально-коммуникативное развитие"]', 3, 9),
(@olympiad_id, 'Обогащение активного словаря — это задача области:', '["Речевое развитие", "Познавательное развитие", "Социально-коммуникативное развитие", "Художественно-эстетическое развитие"]', 0, 10);
