INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Что означает аббревиатура РППС?', '["Развивающая предметно-пространственная среда", "Рабочая программа педагогического сотрудника", "Региональная программа профсопровождения", "Развивающая психолого-педагогическая система"]', 0, 1),
(@olympiad_id, 'Какое свойство РППС означает возможность изменения среды?', '["Полифункциональность", "Трансформируемость", "Вариативность", "Доступность"]', 1, 2),
(@olympiad_id, 'Безопасность РППС предполагает:', '["Соответствие всех элементов требованиям надёжности и безопасности", "Полный запрет мелких предметов", "Отсутствие мебели в группе", "Использование только пластиковых игрушек"]', 0, 3),
(@olympiad_id, 'Содержательная насыщенность РППС означает:', '["Максимальное количество игрушек", "Соответствие возрастным возможностям детей и содержанию программы", "Заполнение всего пространства", "Наличие дорогого оборудования"]', 1, 4),
(@olympiad_id, 'Полифункциональность материалов — это:', '["Возможность использования в разных видах детской активности", "Одноразовое использование", "Использование только фабричных игрушек", "Применение только дидактических пособий"]', 0, 5),
(@olympiad_id, 'Какой принцип обеспечивает свободный выбор детьми материалов?', '["Трансформируемость", "Полифункциональность", "Доступность", "Насыщенность"]', 2, 6),
(@olympiad_id, 'Вариативность РППС предполагает:', '["Единообразие оформления", "Наличие различных пространств и материалов для свободного выбора", "Строгое закрепление мест за детьми", "Один набор игрушек на весь год"]', 1, 7),
(@olympiad_id, 'РППС в группе должна соответствовать:', '["Пожеланиям заведующего", "Возрастным особенностям детей данной группы", "Стандартам оформления офисов", "Требованиям начальной школы"]', 1, 8),
(@olympiad_id, 'Какой центр НЕ является типичным для РППС в ДОУ?', '["Центр познания", "Центр творчества", "Центр бухгалтерского учёта", "Центр конструирования"]', 2, 9),
(@olympiad_id, 'Кто несёт ответственность за создание РППС в группе?', '["Родители воспитанников", "Воспитатель совместно с администрацией ДОУ", "Дети самостоятельно", "Муниципальные органы"]', 1, 10);
INSERT INTO `olympiads` (`title`, `slug`, `description`, `seo_content`, `target_audience`, `subject`, `grade`, `diploma_price`, `is_active`, `display_order`)
INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Центр сюжетно-ролевой игры предназначен для:', '["Проведения занятий по математике", "Развития игровой деятельности и социальных навыков", "Хранения документации воспитателя", "Проведения родительских собраний"]', 1, 1),
(@olympiad_id, 'Какой центр способствует развитию мелкой моторики?', '["Центр физического развития", "Центр художественного творчества", "Центр природы", "Центр отдыха"]', 1, 2),
(@olympiad_id, 'Книжный уголок должен:', '["Находиться в шумной зоне", "Быть в спокойной, хорошо освещённой части группы", "Быть закрыт для детей", "Содержать только учебники"]', 1, 3),
(@olympiad_id, 'Принцип гибкого зонирования означает:', '["Жёсткое разделение перегородками", "Возможность трансформации пространства", "Отсутствие деления пространства", "Закрепление детей за зонами"]', 1, 4),
(@olympiad_id, 'Уголок уединения нужен для:', '["Наказания детей", "Возможности побыть в тишине и восстановить равновесие", "Хранения игрушек", "Проведения индивидуальных занятий"]', 1, 5),
(@olympiad_id, 'Центр экспериментирования включает:', '["Только книги", "Материалы для опытов: лупы, ёмкости, природные материалы", "Только компьютеры", "Спортивный инвентарь"]', 1, 6),
(@olympiad_id, 'Для младшей группы в РППС важно:', '["Преобладание крупных безопасных предметов и пространство для движения", "Максимум мелких деталей", "Письменные инструкции", "Строгое расписание зон"]', 0, 7),
(@olympiad_id, 'Музыкальный уголок содержит:', '["Промышленные инструменты", "Детские музыкальные инструменты, дидактические игры, фонотеку", "Только магнитофон", "Нотную литературу"]', 1, 8),
(@olympiad_id, 'Информационное пространство для родителей включает:', '["Личные дела детей", "Стенды с информацией о жизни группы, меню, объявления", "Финансовую отчётность", "Журнал посещаемости"]', 1, 9),
(@olympiad_id, 'Какой центр предназначен для развития конструктивных навыков?', '["Центр природы", "Центр конструирования", "Центр грамотности", "Центр музыки"]', 1, 10);
