INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Что такое «говорящая среда» в ДОУ?', '["Среда с включённым радио", "Среда, которая информирует ребёнка и направляет его деятельность", "Среда, где только разговаривают", "Среда с голосовыми помощниками"]', 1, 1),
(@olympiad_id, 'Лэпбук в РППС — это:', '["Электронный планшет", "Интерактивная тематическая папка с кармашками и заданиями", "Рабочая тетрадь", "Классный журнал"]', 1, 2),
(@olympiad_id, 'Какой материал является полифункциональным?', '["Конструктор для разных видов деятельности", "Раскраска с одним заданием", "Одноразовая поделка", "Стационарная горка"]', 0, 3),
(@olympiad_id, 'Природный материал (шишки, камни) способствует развитию:', '["Только эстетического вкуса", "Сенсорного восприятия, познавательного интереса и творчества", "Только физической силы", "Только математических способностей"]', 1, 4),
(@olympiad_id, 'Макетирование как элемент РППС — это:', '["Создание объёмных моделей-макетов для игры и познания", "Изготовление макияжа", "Составление расписания", "Ремонт помещения"]', 0, 5),
(@olympiad_id, 'Интерактивная стена используется для:', '["Размещения запрещающих знаков", "Организации развивающих элементов для взаимодействия ребёнка", "Показа рекламы", "Просмотра фильмов"]', 1, 6),
(@olympiad_id, 'Принцип динамичности РППС предполагает:', '["Стабильность на весь год", "Периодическую сменяемость материалов", "Статичность среды", "Единообразие"]', 1, 7),
(@olympiad_id, 'Бизиборд — это:', '["Доска для деловых заметок", "Развивающая доска с элементами для тактильного и моторного развития", "Электронная доска", "Магнитная доска для букв"]', 1, 8),
(@olympiad_id, 'Как часто обновлять содержание центров активности?', '["Один раз в год", "Регулярно, в зависимости от темы недели и интересов детей", "Никогда", "Только при проверке"]', 1, 9),
(@olympiad_id, 'Исследовательский подход к среде побуждает ребёнка к:', '["Пассивному наблюдению", "Самостоятельному исследованию и открытию", "Заучиванию правил", "Копированию действий воспитателя"]', 1, 10);
