INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Какой вид игры является ведущей деятельностью дошкольника?', '["Дидактическая", "Сюжетно-ролевая", "Подвижная", "Компьютерная"]', 1, 1),
(@olympiad_id, 'Кто определил игру как ведущую деятельность дошкольника?', '["Л.С. Выготский и Д.Б. Эльконин", "И.П. Павлов", "К.Д. Ушинский", "А.С. Макаренко"]', 0, 2),
(@olympiad_id, 'Дидактическая игра отличается тем, что:', '["Не имеет правил", "Имеет обучающую задачу и чёткие правила", "Проводится только на улице", "Не требует воспитателя"]', 1, 3),
(@olympiad_id, 'Режиссёрская игра — это:', '["Игра режиссёра", "Игра, где ребёнок управляет игрушками-персонажами, создавая сюжет", "Постановка спектакля", "Игра по сценарию воспитателя"]', 1, 4),
(@olympiad_id, 'Наиболее эффективная роль воспитателя в игре:', '["Строгий контролёр", "Партнёр и наблюдатель, поддерживающий инициативу", "Полное невмешательство", "Единственный ведущий"]', 1, 5),
(@olympiad_id, 'Театрализованная игра способствует развитию:', '["Только физических навыков", "Речи, эмоциональной сферы, творческих способностей", "Только математики", "Только чтения"]', 1, 6),
(@olympiad_id, 'Строительно-конструктивные игры развивают:', '["Только моторику", "Пространственное мышление, воображение, конструктивные навыки", "Только физическую силу", "Только речь"]', 1, 7),
(@olympiad_id, 'Подвижная игра с правилами формирует:', '["Только быстроту", "Умение действовать по правилам, ловкость, волевые качества", "Только соревновательность", "Только агрессию"]', 1, 8),
(@olympiad_id, 'Что НЕ относится к компонентам дидактической игры?', '["Обучающая задача", "Игровое действие", "Правила", "Домашнее задание"]', 3, 9),
(@olympiad_id, 'Игра-драматизация — это:', '["Конфликт между детьми", "Разыгрывание литературного произведения по ролям", "Просмотр мультфильмов", "Пересказ текста воспитателем"]', 1, 10);
