INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Основные компоненты сюжетно-ролевой игры:', '["Оценка воспитателя", "Сюжет, роль, игровые действия", "Домашнее задание", "Контрольная работа"]', 1, 1),
(@olympiad_id, 'В каком возрасте сюжетно-ролевая игра наиболее развита?', '["1-2 года", "5-6 лет", "7-8 лет", "10-12 лет"]', 1, 2),
(@olympiad_id, 'Источник сюжетов для ролевых игр:', '["Только мультфильмы", "Окружающая действительность и опыт ребёнка", "Только книги", "Только указания воспитателя"]', 1, 3),
(@olympiad_id, 'Для младших дошкольников характерны:', '["Игры с развёрнутым сюжетом", "Предметно-игровые действия и манипуляции", "Сложные режиссёрские игры", "Ролевые игры с конфликтами"]', 1, 4),
(@olympiad_id, 'Обогатить содержание игры можно через:', '["Запреты", "Экскурсии, чтение, беседы, расширяющие кругозор", "Невмешательство", "Навязывание сюжетов"]', 1, 5),
(@olympiad_id, 'Замещение в игре — это:', '["Наказание", "Использование предмета-заместителя вместо реального", "Замена воспитателя", "Перенос игры"]', 1, 6),
(@olympiad_id, 'Какой атрибут НЕ типичен для игры «Больница»?', '["Халат врача", "Фонендоскоп", "Кассовый аппарат", "Бинты (игрушечные)"]', 2, 7),
(@olympiad_id, 'Совместная игра развивает:', '["Только индивидуализм", "Коммуникативные навыки, умение договариваться", "Только физику", "Только память"]', 1, 8),
(@olympiad_id, 'Старшие дошкольники в игре способны:', '["Только повторять действия воспитателя", "Планировать игру, распределять роли, развивать сюжет", "Только играть одни", "Только копировать мультфильмы"]', 1, 9),
(@olympiad_id, 'Игровая позиция воспитателя:', '["Контроль и оценивание", "Включение в игру как партнёра, не разрушая замысел", "Полное устранение", "Навязывание правил"]', 1, 10);
