INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Основная цель дидактической игры:', '["Развлечение", "Решение обучающих задач в игровой форме", "Заполнение времени", "Подготовка к экзаменам"]', 1, 1),
(@olympiad_id, 'Что НЕ входит в структуру дидактической игры?', '["Дидактическая задача", "Правила", "Игровое действие", "Выставление оценок"]', 3, 2),
(@olympiad_id, 'Дидактические игры с предметами используют:', '["Только карточки", "Реальные предметы, игрушки, природный материал", "Только компьютер", "Только книги"]', 1, 3),
(@olympiad_id, 'Настольно-печатная игра — это:', '["Подвижная игра", "Лото, домино, парные картинки", "Компьютерная игра", "Сюжетно-ролевая игра"]', 1, 4),
(@olympiad_id, 'Словесные дидактические игры развивают:', '["Только физику", "Речь, мышление, внимание, память", "Только музыку", "Только рисование"]', 1, 5),
(@olympiad_id, 'При подборе игры воспитатель учитывает:', '["Стоимость материалов", "Возраст детей и программную задачу", "Своё настроение", "Мнение заведующего"]', 1, 6),
(@olympiad_id, 'Игра для развития математических представлений:', '["Угадай, чей голос", "Посчитай и сравни", "Назови ласково", "Кто где живёт"]', 1, 7),
(@olympiad_id, 'Роль воспитателя в дидактической игре:', '["Только наблюдатель", "Организатор, руководитель и иногда участник", "Оценщик", "Не участвует"]', 1, 8),
(@olympiad_id, 'Повторность дидактических игр:', '["Недопустима", "Необходима для закрепления, с постепенным усложнением", "Только один раз", "Вредна"]', 1, 9),
(@olympiad_id, 'Сенсорные игры направлены на развитие:', '["Восприятия цвета, формы, величины, тактильных ощущений", "Только слуха", "Только зрения", "Только обоняния"]', 0, 10);
