INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Что такое системно-деятельностный подход в обучении?', '["Заучивание материала наизусть", "Организация учебного процесса, в котором ученик активно действует и познаёт", "Списывание с доски", "Только устный опрос"]', 1, 1),
(@olympiad_id, 'Какой метод обучения основан на постановке проблемы перед учащимися?', '["Проблемное обучение", "Репродуктивный метод", "Диктант", "Списывание"]', 0, 2),
(@olympiad_id, 'Что такое дифференцированный подход?', '["Одинаковые задания для всех", "Учёт индивидуальных особенностей и уровня подготовки учеников", "Работа только с отличниками", "Отмена домашних заданий"]', 1, 3),
(@olympiad_id, 'Метод проектов в школе предполагает:', '["Копирование текста из учебника", "Самостоятельную работу учащихся по решению практической задачи", "Только фронтальный опрос", "Заучивание определений"]', 1, 4),
(@olympiad_id, 'Что такое формирующее оценивание?', '["Итоговая контрольная работа", "Оценивание в процессе обучения для корректировки учебной деятельности", "Выставление оценок за четверть", "Экзамен"]', 1, 5),
(@olympiad_id, 'Групповая работа на уроке способствует:', '["Только дисциплине", "Развитию коммуникативных навыков и умения сотрудничать", "Только запоминанию", "Только контролю знаний"]', 1, 6),
(@olympiad_id, 'Что такое технологическая карта урока?', '["Карта школьного здания", "Документ, описывающий ход урока с указанием деятельности учителя и учеников", "Карта учебной территории", "Расписание звонков"]', 1, 7),
(@olympiad_id, 'Рефлексия на уроке — это:', '["Выставление оценок", "Осмысление учениками своей деятельности и её результатов", "Домашнее задание", "Физминутка"]', 1, 8),
(@olympiad_id, 'Какой приём помогает активизировать мышление в начале урока?', '["Продолжительная лекция", "Проблемный вопрос или ситуация", "Списывание с доски", "Молчаливое чтение"]', 1, 9),
(@olympiad_id, 'Индивидуальный подход в обучении означает:', '["Игнорирование особенностей учеников", "Учёт способностей, интересов и темпа работы каждого ученика", "Работу только с одним учеником", "Отмену уроков"]', 1, 10);
