(@olympiad_id, 'Какая буква стоит первой в русском алфавите?', '["Б", "В", "А", "Г"]', 2, 1),
(@olympiad_id, 'С какой буквы начинается слово «Мама»?', '["П", "Н", "Л", "М"]', 3, 2),
(@olympiad_id, 'Сколько слогов в слове «ко-ро-ва»?', '["1", "2", "3", "4"]', 2, 3),
(@olympiad_id, 'Какая буква стоит последней в русском алфавите?', '["Э", "Ю", "Я", "Ъ"]', 2, 4),
(@olympiad_id, 'С какого звука начинается слово «Кот»?', '["О", "Т", "К", "А"]', 2, 5),
(@olympiad_id, 'Какое слово начинается на букву «Д»?', '["Кошка", "Белка", "Дом", "Слон"]', 2, 6),
(@olympiad_id, 'Сколько гласных звуков в слове «Луна»?', '["1", "2", "3", "4"]', 1, 7),
(@olympiad_id, 'Какая буква похожа на домик с трубой?', '["О", "П", "Д", "С"]', 2, 8),
(@olympiad_id, 'Что получится, если соединить звуки М-А-М-А?', '["Папа", "Мама", "Баба", "Каша"]', 1, 9),
(@olympiad_id, 'Какое из этих слов самое короткое?', '["Бегемот", "Слон", "Кот", "Крокодил"]', 2, 10);
