INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Зимой и летом одним цветом. Что это?', '["Берёза", "Ёлка", "Дуб", "Клён"]', 1, 1),
(@olympiad_id, 'Сидит дед, во сто шуб одет. Кто его раздевает — тот слёзы проливает. Что это?', '["Чеснок", "Картошка", "Лук", "Морковь"]', 2, 2),
(@olympiad_id, 'Без рук, без ног, а рисовать умеет. Что это?', '["Кисточка", "Карандаш", "Мороз", "Ветер"]', 2, 3),
(@olympiad_id, 'Кто зимой холодной ходит злой, голодный?', '["Заяц", "Медведь", "Волк", "Лиса"]', 2, 4),
(@olympiad_id, 'Красна девица сидит в темнице, а коса на улице. Что это?', '["Свёкла", "Морковь", "Репка", "Лук"]', 1, 5),
(@olympiad_id, 'Два братца через дорогу живут, а друг друга не видят. Что это?', '["Руки", "Ноги", "Глаза", "Уши"]', 2, 6),
(@olympiad_id, 'Висит груша — нельзя скушать. Что это?', '["Яблоко", "Лампочка", "Шарик", "Мяч"]', 1, 7),
(@olympiad_id, 'Летом серый, зимой белый. Кто это?', '["Волк", "Медведь", "Лиса", "Заяц"]', 3, 8),
(@olympiad_id, 'Течёт-течёт — не вытечет, бежит-бежит — не выбежит. Что это?', '["Дорога", "Река", "Ветер", "Облако"]', 1, 9),
(@olympiad_id, 'Не огонь, а жжётся. Что это?', '["Солнце", "Лампа", "Крапива", "Перец"]', 2, 10);
