INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Что сначала делают утром: завтракают или просыпаются?', '["Завтракают", "Просыпаются", "Обедают", "Гуляют"]', 1, 1),
(@olympiad_id, 'Если на картинке мальчик держит зонт, какая погода на улице?', '["Солнечная", "Дождливая", "Снежная", "Ветреная"]', 1, 2),
(@olympiad_id, 'Что надевают зимой, чтобы не замёрзнуть?', '["Шорты и майку", "Шубу и шапку", "Купальник", "Панамку"]', 1, 3),
(@olympiad_id, 'На картинке девочка поливает цветок. Чем она поливает?', '["Кастрюлей", "Лейкой", "Тарелкой", "Чашкой"]', 1, 4),
(@olympiad_id, 'Если ребёнок плачет, как он себя чувствует?', '["Весело", "Грустно", "Скучно", "Смешно"]', 1, 5),
(@olympiad_id, 'Что нужно сделать перед едой?', '["Поиграть", "Помыть руки", "Поспать", "Порисовать"]', 1, 6),
(@olympiad_id, 'На картинке: сначала яйцо, потом цыплёнок, потом... кто?', '["Утка", "Рыбка", "Курица", "Кошка"]', 2, 7),
(@olympiad_id, 'Мальчик бросил мяч вверх. Что произойдёт дальше?', '["Мяч улетит в космос", "Мяч упадёт вниз", "Мяч исчезнет", "Мяч станет больше"]', 1, 8),
(@olympiad_id, 'Если на картинке дети сидят за партами и слушают учителя — где они?', '["В магазине", "В больнице", "В школе (на занятии)", "На улице"]', 2, 9),
(@olympiad_id, 'Девочка кормит кота из миски. Кто ест — девочка или кот?', '["Девочка", "Кот", "Оба", "Никто"]', 1, 10);
