INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Логопедическое обследование ребёнка начинается с:', '["Постановки звуков", "Сбора анамнеза и изучения документации", "Артикуляционной гимнастики", "Обучения грамоте"]', 1, 1),
(@olympiad_id, 'Какой принцип логопедической диагностики предполагает изучение речи во взаимосвязи с другими сторонами развития?', '["Принцип системности", "Принцип доступности", "Принцип наглядности", "Принцип индивидуального подхода"]', 0, 2),
(@olympiad_id, 'Речевая карта — это:', '["Географическая карта диалектов", "Документ, фиксирующий результаты логопедического обследования", "Расписание занятий логопеда", "Список детей логопедической группы"]', 1, 3),
(@olympiad_id, 'Онтогенез речи — это:', '["Нарушение речи", "Индивидуальное развитие речи от рождения до зрелости", "Метод коррекции", "Вид дислалии"]', 1, 4),
(@olympiad_id, 'Какой метод позволяет оценить речь ребёнка в естественных условиях?', '["Тестирование", "Наблюдение", "Анкетирование родителей", "Аппаратная диагностика"]', 1, 5),
(@olympiad_id, 'Фонематический слух — это способность:', '["Слышать громкие звуки", "Различать и узнавать фонемы родного языка", "Воспроизводить музыкальные мелодии", "Определять направление звука"]', 1, 6),
(@olympiad_id, 'Обследование словарного запаса включает проверку:', '["Только активного словаря", "Активного и пассивного словаря", "Только пассивного словаря", "Только бытовой лексики"]', 1, 7),
(@olympiad_id, 'Заключение логопеда оформляется:', '["Устно, без записи", "В речевой карте с указанием структуры и механизма нарушения", "Только в журнале посещений", "Только для врача"]', 1, 8),
(@olympiad_id, 'Принцип динамического изучения предполагает:', '["Однократное обследование", "Оценку актуального уровня и зоны ближайшего развития", "Только констатацию дефекта", "Обследование только в конце года"]', 1, 9),
(@olympiad_id, 'Для обследования речи детей раннего возраста преимущественно используют:', '["Письменные тесты", "Игровые ситуации и предметную деятельность", "Диктанты", "Пересказ сложных текстов"]', 1, 10);
