INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'При обследовании звукопроизношения проверяется произнесение звука:', '["Только в начале слова", "В разных позициях: начале, середине и конце слова", "Только в конце слова", "Только в слогах"]', 1, 1),
(@olympiad_id, 'Дислалия — это нарушение:', '["Темпа речи", "Звукопроизношения при нормальном слухе и сохранной иннервации речевого аппарата", "Голоса", "Письменной речи"]', 1, 2),
(@olympiad_id, 'Сигматизм — это нарушение произношения:', '["Звуков [р] и [р\u0027]", "Свистящих и шипящих звуков", "Звуков [л] и [л\u0027]", "Заднеязычных звуков"]', 1, 3),
(@olympiad_id, 'Ротацизм — это нарушение произношения:', '["Свистящих звуков", "Шипящих звуков", "Звуков [р] и [р\u0027]", "Губных звуков"]', 2, 4),
(@olympiad_id, 'Ламбдацизм — это нарушение произношения:', '["Звуков [р] и [р\u0027]", "Звуков [л] и [л\u0027]", "Свистящих звуков", "Заднеязычных звуков"]', 1, 5),
(@olympiad_id, 'Замена одного звука другим в речи ребёнка называется:', '["Искажение", "Пропуск", "Параσигматизм (замена)", "Смешение"]', 2, 6),
(@olympiad_id, 'Для обследования звукопроизношения используют:', '["Таблицу Сивцева", "Предметные картинки с заданным звуком в разных позициях", "Музыкальные инструменты", "Геометрические фигуры"]', 1, 7),
(@olympiad_id, 'Какой вид нарушения звукопроизношения при дислалии — лишний?', '["Отсутствие звука", "Замена звука", "Искажение звука", "Заикание"]', 3, 8),
(@olympiad_id, 'При обследовании звукопроизношения также важно проверить:', '["Только изолированное произношение", "Произношение звука в самостоятельной связной речи", "Только повторение за логопедом", "Только шёпотную речь"]', 1, 9),
(@olympiad_id, 'Возрастная норма формирования всех звуков русского языка:', '["К 3 годам", "К 5-6 годам", "К 10 годам", "К 1 году"]', 1, 10);
