INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Дисграфия — это:', '["Нарушение звукопроизношения", "Стойкое нарушение процесса письма", "Нарушение темпа речи", "Нарушение голоса"]', 1, 1),
(@olympiad_id, 'Дислексия — это:', '["Нарушение письма", "Стойкое нарушение процесса чтения", "Нарушение счёта", "Нарушение слуха"]', 1, 2),
(@olympiad_id, 'Оптическая дисграфия связана с нарушением:', '["Фонематического слуха", "Зрительного восприятия и пространственных представлений", "Темпа речи", "Голоса"]', 1, 3),
(@olympiad_id, 'Артикуляторно-акустическая дисграфия проявляется в:', '["Зеркальном написании букв", "Заменах букв на письме, соответствующих заменам звуков в устной речи", "Пропусках целых слов", "Нарушении почерка"]', 1, 4),
(@olympiad_id, 'Дисграфия на основе нарушения фонемного распознавания проявляется в:', '["Неправильном написании имён", "Заменах букв, обозначающих фонетически близкие звуки", "Нарушении почерка", "Пропусках строк"]', 1, 5),
(@olympiad_id, 'Аграмматическая дисграфия связана с:', '["Нарушением оптических представлений", "Недоразвитием лексико-грамматического строя речи", "Нарушением моторики руки", "Снижением слуха"]', 1, 6),
(@olympiad_id, 'Для диагностики дисграфии используют:', '["Только устный опрос", "Анализ письменных работ: диктанты, списывание, самостоятельное письмо", "Только проверку чтения", "Только рисуночные тесты"]', 1, 7),
(@olympiad_id, 'Специфические ошибки при дисграфии отличаются от орфографических тем, что:', '["Они встречаются реже", "Они стойкие, повторяющиеся и не связаны с незнанием правил", "Они исчезают без коррекции", "Они бывают только у взрослых"]', 1, 8),
(@olympiad_id, 'Обследование письменной речи целесообразно начинать с:', '["Диктанта сложного текста", "Изучения тетрадей и анализа типичных ошибок", "Сочинения", "Изложения"]', 1, 9),
(@olympiad_id, 'Дисграфию следует дифференцировать от:', '["Заикания", "Трудностей письма, обусловленных педагогической запущенностью или незнанием языка", "Ринолалии", "Алалии"]', 1, 10);
