INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Первый этап коррекции звукопроизношения — это:', '["Автоматизация звука", "Подготовительный этап (развитие артикуляционной моторики)", "Дифференциация звуков", "Введение звука в связную речь"]', 1, 1),
(@olympiad_id, 'Артикуляционная гимнастика проводится для:', '["Развития мелкой моторики рук", "Подготовки органов артикуляции к правильному произношению звуков", "Развития слуха", "Обучения чтению"]', 1, 2),
(@olympiad_id, 'Постановка звука по подражанию — это:', '["Механическое воздействие на язык", "Воспроизведение звука по образцу логопеда", "Постановка с помощью зонда", "Использование компьютерных программ"]', 1, 3),
(@olympiad_id, 'Механический способ постановки звука предполагает:', '["Только показ артикуляции", "Использование логопедических зондов или шпателя для придания нужного положения органам артикуляции", "Прослушивание аудиозаписей", "Чтение вслух"]', 1, 4),
(@olympiad_id, 'Смешанный способ постановки звука сочетает:', '["Только подражание", "Подражание и механическую помощь", "Только зондовый массаж", "Только дыхательные упражнения"]', 1, 5),
(@olympiad_id, 'При постановке звука [р] часто используется приём:', '["Надувание щёк", "Вибрация кончика языка от звука [д] или с механической помощью", "Вытягивание губ трубочкой", "Прикусывание нижней губы"]', 1, 6),
(@olympiad_id, 'Звук [ш] ставится от:', '["Звука [р]", "Звука [с] с изменением положения языка (поднятием вверх)", "Звука [м]", "Звука [к]"]', 1, 7),
(@olympiad_id, 'Постановка звука считается завершённой, когда ребёнок:', '["Произносит звук изолированно", "Правильно произносит звук изолированно по инструкции логопеда", "Использует звук в связной речи", "Различает звук на слух"]', 1, 8),
(@olympiad_id, 'Логопедический зонд — это:', '["Медицинский прибор для измерения температуры", "Специальный инструмент для механической постановки звуков", "Компьютерная программа", "Вид дидактической игры"]', 1, 9),
(@olympiad_id, 'Перед постановкой звука необходимо:', '["Сразу автоматизировать звук", "Определить причину нарушения и подготовить артикуляционный аппарат", "Обучить ребёнка чтению", "Провести диктант"]', 1, 10);
