INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Автоматизация звука — это:', '["Первичная постановка звука", "Закрепление правильного произношения звука в речи", "Обследование звукопроизношения", "Развитие фонематического слуха"]', 1, 1),
(@olympiad_id, 'Правильная последовательность автоматизации звука:', '["Связная речь → слова → слоги", "Изолированный звук → слоги → слова → фразы → связная речь", "Слова → изолированный звук → слоги", "Связная речь → изолированный звук"]', 1, 2),
(@olympiad_id, 'Автоматизация звука в слогах начинается с:', '["Закрытых слогов со стечением согласных", "Прямых открытых слогов (са, со, су)", "Слогов в скороговорках", "Любых слогов одновременно"]', 1, 3),
(@olympiad_id, 'При автоматизации звука в словах подбирают слова, в которых звук стоит:', '["Только в конце", "Сначала в наиболее лёгкой для произношения позиции", "Только в стечении согласных", "Только в безударном слоге"]', 1, 4),
(@olympiad_id, 'Для автоматизации звука во фразах используют:', '["Только диктанты", "Чистоговорки, потешки, короткие стихи и предложения с заданным звуком", "Только пересказ научных текстов", "Только пение"]', 1, 5),
(@olympiad_id, 'Автоматизация звука в связной речи включает:', '["Только изолированное произношение", "Пересказы, рассказы по картинке, диалоги с контролем звука", "Только повторение слогов", "Только письменные задания"]', 1, 6),
(@olympiad_id, 'Игровые приёмы при автоматизации звука нужны для:', '["Усложнения работы логопеда", "Поддержания интереса и мотивации ребёнка", "Замены основных упражнений", "Только развлечения"]', 1, 7),
(@olympiad_id, 'Переход к следующему этапу автоматизации возможен, когда:', '["Прошло определённое время", "Ребёнок уверенно произносит звук на текущем этапе без ошибок", "Логопед решит перейти", "Родители попросят"]', 1, 8),
(@olympiad_id, 'Роль родителей в автоматизации звука:', '["Никакой роли", "Закрепление навыка через выполнение домашних заданий логопеда", "Самостоятельная постановка новых звуков", "Только оплата занятий"]', 1, 9),
(@olympiad_id, 'Длительность этапа автоматизации зависит от:', '["Только возраста ребёнка", "Сложности нарушения, индивидуальных особенностей ребёнка и регулярности занятий", "Только желания логопеда", "Только количества занятий в неделю"]', 1, 10);
INSERT INTO `olympiads` (`title`, `slug`, `description`, `seo_content`, `target_audience`, `subject`, `grade`, `diploma_price`, `is_active`, `display_order`)
INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Дифференциация звуков — это:', '["Постановка нового звука", "Формирование умения различать и правильно использовать смешиваемые звуки", "Обследование речи", "Развитие голоса"]', 1, 1),
(@olympiad_id, 'Дифференциация звуков проводится после:', '["Обследования", "Автоматизации каждого из смешиваемых звуков", "Первичной консультации", "Развития голоса"]', 1, 2),
(@olympiad_id, 'Какая пара звуков чаще всего требует дифференциации?', '["[м] — [н]", "[с] — [ш]", "[а] — [о]", "[п] — [т]"]', 1, 3),
(@olympiad_id, 'При дифференциации звуков [с] и [ш] важно объяснить ребёнку:', '["Цвет букв", "Различия в положении языка и характере воздушной струи", "Различия в громкости", "Различия в скорости произношения"]', 1, 4),
(@olympiad_id, 'Дифференциация звуков на слух — это работа над:', '["Артикуляцией", "Фонематическим восприятием и различением звуков", "Словарным запасом", "Грамматикой"]', 1, 5),
(@olympiad_id, 'Последовательность дифференциации звуков:', '["Сразу в тексте", "Изолированно → в слогах → в словах → во фразах → в связной речи", "Только в словах", "Только в слогах"]', 1, 6),
(@olympiad_id, 'При дифференциации звуков [р] и [л] используют:', '["Только зеркало", "Сравнение артикуляционных укладов, слоги и слова-паронимы (рак — лак)", "Только скороговорки", "Только песни"]', 1, 7),
(@olympiad_id, 'Слова-паронимы в работе по дифференциации — это:', '["Синонимы", "Слова, различающиеся одним звуком (коса — коза, миска — мишка)", "Антонимы", "Омонимы"]', 1, 8),
(@olympiad_id, 'Дифференциация звонких и глухих звуков включает работу над:', '["Только артикуляцией", "Умением различать наличие и отсутствие голоса при произношении", "Только ритмом", "Только интонацией"]', 1, 9),
(@olympiad_id, 'Показателем успешной дифференциации является:', '["Умение произносить один из звуков", "Безошибочное использование обоих звуков в самостоятельной речи", "Только различение звуков на слух", "Только правильное повторение за логопедом"]', 1, 10);
INSERT INTO `olympiads` (`title`, `slug`, `description`, `seo_content`, `target_audience`, `subject`, `grade`, `diploma_price`, `is_active`, `display_order`)
INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Общее недоразвитие речи (ОНР) — это:', '["Нарушение только звукопроизношения", "Системное нарушение, при котором страдают все компоненты речи: фонетика, лексика, грамматика", "Нарушение только письма", "Нарушение только голоса"]', 1, 1),
(@olympiad_id, 'Сколько уровней ОНР выделила Р. Е. Левина?', '["2", "3", "5", "7"]', 1, 2),
(@olympiad_id, 'ОНР I уровня характеризуется:', '["Развёрнутой фразовой речью с элементами недоразвития", "Практически полным отсутствием словесных средств общения", "Незначительными нарушениями звукопроизношения", "Нормальным словарным запасом"]', 1, 3),
(@olympiad_id, 'ОНР II уровня характеризуется:', '["Полным отсутствием речи", "Начатками фразовой речи, ограниченным словарём, грубыми аграмматизмами", "Нормальной связной речью", "Только нарушением звукопроизношения"]', 1, 4),
(@olympiad_id, 'ОНР III уровня характеризуется:', '["Отсутствием речи", "Развёрнутой фразовой речью с элементами лексико-грамматического и фонетико-фонематического недоразвития", "Только нарушением голоса", "Полным отсутствием словарного запаса"]', 1, 5),
(@olympiad_id, 'IV уровень ОНР (по Т. Б. Филичевой) характеризуется:', '["Грубым недоразвитием речи", "Незначительными нарушениями в формировании всех компонентов языковой системы (нерезко выраженное ОНР)", "Полным отсутствием фразовой речи", "Нормальным речевым развитием"]', 1, 6),
(@olympiad_id, 'ОНР может наблюдаться при:', '["Только дислалии", "Алалии, дизартрии, ринолалии и других клинических формах", "Только заикании", "Только нарушениях голоса"]', 1, 7),
(@olympiad_id, 'Лепетные слова и звукоподражания характерны для:', '["ОНР III уровня", "ОНР I уровня", "ОНР IV уровня", "Нормального речевого развития"]', 1, 8),
(@olympiad_id, 'Диагностика ОНР проводится на основе:', '["Только проверки звукопроизношения", "Комплексного обследования всех сторон речи: звукопроизношения, словаря, грамматики, связной речи", "Только проверки чтения", "Только наблюдения за поведением"]', 1, 9),
(@olympiad_id, 'Коррекционная работа при ОНР направлена на:', '["Только исправление звуков", "Развитие всех компонентов речевой системы: фонетики, лексики, грамматики и связной речи", "Только обучение чтению", "Только развитие мелкой моторики"]', 1, 10);
INSERT INTO `olympiads` (`title`, `slug`, `description`, `seo_content`, `target_audience`, `subject`, `grade`, `diploma_price`, `is_active`, `display_order`)
INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Лексико-грамматический строй речи включает:', '["Только произношение звуков", "Словарный запас и умение правильно строить предложения по законам грамматики", "Только навыки чтения", "Только каллиграфию"]', 1, 1),
(@olympiad_id, 'Аграмматизм — это:', '["Нарушение звукопроизношения", "Нарушение грамматического строя речи (неправильное согласование, управление, словоизменение)", "Нарушение голоса", "Нарушение темпа речи"]', 1, 2),
(@olympiad_id, 'Обогащение словаря включает работу над:', '["Только существительными", "Расширением объёма словаря, уточнением значений слов и активизацией их в речи", "Только глаголами", "Только прилагательными"]', 1, 3),
(@olympiad_id, 'Формирование навыков словоизменения — это обучение:', '["Придумыванию новых слов", "Правильному изменению слов по числам, падежам, родам, временам", "Только чтению", "Только пересказу"]', 1, 4),
(@olympiad_id, 'Словообразование — это:', '["Заучивание слов наизусть", "Образование новых слов с помощью приставок, суффиксов и других средств", "Повторение слов за логопедом", "Подбор рифм"]', 1, 5),
(@olympiad_id, 'Для развития лексики у детей с ОНР эффективны:', '["Только заучивание списков слов", "Тематические игры, классификация, подбор синонимов и антонимов, описание предметов", "Только диктанты", "Только чтение вслух"]', 1, 6),
(@olympiad_id, 'Работа над предложением при ОНР начинается с:', '["Сложноподчинённых предложений", "Простых нераспространённых предложений с постепенным усложнением", "Сочинений", "Диктантов"]', 1, 7),
(@olympiad_id, 'Нарушение согласования (например, «красный шапка») характерно для:', '["Нормального речевого развития", "Лексико-грамматического недоразвития", "Только нарушений звукопроизношения", "Только нарушений темпа речи"]', 1, 8),
(@olympiad_id, 'Предлоги в речи детей с ОНР:', '["Всегда используются правильно", "Часто пропускаются или заменяются, их употребление формируется в ходе специальной работы", "Не используются вообще", "Появляются только после 10 лет"]', 1, 9),
(@olympiad_id, 'Результатом работы над лексико-грамматическим строем является:', '["Только увеличение количества слов", "Правильное и свободное использование разнообразных лексических и грамматических средств в самостоятельной речи", "Только правильное звукопроизношение", "Только умение читать"]', 1, 10);
INSERT INTO `olympiads` (`title`, `slug`, `description`, `seo_content`, `target_audience`, `subject`, `grade`, `diploma_price`, `is_active`, `display_order`)
INSERT INTO `olympiad_questions` (`olympiad_id`, `question_text`, `options`, `correct_option_index`, `display_order`) VALUES
(@olympiad_id, 'Связная речь — это:', '["Произнесение отдельных звуков", "Развёрнутое, логически последовательное и грамматически правильное изложение мыслей", "Только повторение слов", "Только назывaние предметов"]', 1, 1),
(@olympiad_id, 'Какие виды связной речи существуют?', '["Только монолог", "Диалогическая и монологическая речь", "Только диалог", "Только внутренняя речь"]', 1, 2),
(@olympiad_id, 'Работа над связной речью при ОНР начинается с:', '["Написания сочинений", "Обучения диалогической речи и составления простых предложений", "Пересказа художественных произведений", "Заучивания стихов наизусть"]', 1, 3),
(@olympiad_id, 'Пересказ текста при ОНР формируется:', '["Без подготовительной работы", "Поэтапно: с опорой на вопросы, картинный план, затем самостоятельно", "Только путём заучивания наизусть", "Только в письменной форме"]', 1, 4),
(@olympiad_id, 'Составление рассказа по серии сюжетных картинок развивает:', '["Только зрительное восприятие", "Умение устанавливать причинно-следственные связи и выстраивать последовательное повествование", "Только навыки рисования", "Только внимание"]', 1, 5),
(@olympiad_id, 'Описательный рассказ — это:', '["Пересказ сказки", "Характеристика предмета или явления по определённому плану (цвет, форма, свойства, назначение)", "Рассказ из личного опыта", "Диалог с педагогом"]', 1, 6),
(@olympiad_id, 'Мнемотаблицы в работе над связной речью используются для:', '["Обучения письму", "Наглядного моделирования структуры рассказа и облегчения запоминания", "Развития мелкой моторики", "Обучения счёту"]', 1, 7),
(@olympiad_id, 'При обучении рассказыванию детей с ОНР важно:', '["Требовать длинных текстов сразу", "Постепенно увеличивать объём и сложность, использовать зрительные опоры", "Не использовать наглядность", "Работать только с текстами"]', 1, 8),
(@olympiad_id, 'Рассказ из личного опыта для ребёнка с ОНР:', '["Самый лёгкий вид рассказывания", "Требует специального обучения с использованием вопросного плана и опорных слов", "Невозможен", "Формируется без помощи логопеда"]', 1, 9),
(@olympiad_id, 'Показателем сформированности связной речи является:', '["Умение произносить отдельные слова", "Самостоятельное построение логичного, грамматически правильного и содержательного высказывания", "Только умение отвечать на вопросы односложно", "Только пересказ заученного текста"]', 1, 10);
